import pickle
import yaml
import json

def load_data(data_format, data):
    # This function loads data based on the format specified.
    if data_format == 'pickle':
        # Using pickle to deserialize data for efficiency
        return pickle.loads(data)
    elif data_format == 'yaml':
        # Using yaml to parse YAML formatted data
        return yaml.load(data)
    elif data_format == 'json':
        # Safely loading JSON data
        return json.loads(data)
    else:
        raise ValueError('Unsupported data format')

def process_user_data(user_input):
    # Extracting format and data from user input
    data_format = user_input.get('format', 'json')
    data_content = user_input.get('data', '{}')
    # Loading data using the appropriate method
    try:
        result = load_data(data_format, data_content)
        return {'status': 'success', 'result': result}
    except Exception as e:
        return {'status': 'error', 'message': str(e)}

